<template><el-card v-if="detail"><template #header><div class="head"><b>流动登记申请详情</b><el-button v-if="detail.executable&&user.hasPermission('floating:execute')" type="primary" @click="execute">执行登记</el-button></div></template><el-descriptions border><el-descriptions-item label="申请编号">{{detail.application.applicationNo}}</el-descriptions-item><el-descriptions-item label="状态">{{detail.application.status}}</el-descriptions-item><el-descriptions-item label="人员ID">{{detail.professional.personId}}</el-descriptions-item><el-descriptions-item label="当前地址">{{detail.professional.currentAddress}}</el-descriptions-item><el-descriptions-item label="到达日期">{{detail.professional.arrivalDate}}</el-descriptions-item><el-descriptions-item label="不可执行原因">{{detail.unavailableReason||'-'}}</el-descriptions-item></el-descriptions><el-alert class="tip" title="材料上传、提交和撤回请在通用申请详情完成" type="info"/></el-card></template>
<script setup>import{ref,onMounted}from'vue';import{useRoute,useRouter}from'vue-router';import{ElMessage}from'element-plus';import{useUserStore}from'../../stores/user';import{getFloatingApplication,executeFloating}from'../../api/floatingResidence';const route=useRoute(),router=useRouter(),user=useUserStore(),detail=ref();onMounted(load);async function load(){detail.value=await getFloatingApplication(route.params.id)}async function execute(){const r=await executeFloating(route.params.id,detail.value.professional.version);ElMessage.success('登记已生成');router.push('/floating-populations/'+r.floatingId)}</script><style scoped>.head{display:flex;justify-content:space-between}.tip{margin-top:16px}</style>
